<span class="line"><span style="color:#89B4FA;font-style:italic;">        assert_eq!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">event</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">data</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;line one</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">line two&quot;</span><span style="color:#9399B2;">);</span></span>
